#include<bits/stdc++.h>
using namespace std;

#define MAX 2147483647
long long f[100001], s[100001], n, m, st;
bool v[100001];
struct node {
	long long x;
	long long y;

};
struct cmp {
	bool operator()(node a, node b) {
		return a.y>b.y;
	}
};
vector<int> a[100001][2];
priority_queue<node,vector<node>,cmp> q;
inline void di(int xx) {

	int x=xx;
	while (!q.empty()) {


        node now = q.top();
		q.pop();
		if (v[now.x]) continue;
        x=now.x;
        v[x] = 1;
        for (int i = 0; i < a[x][0].size(); i++) {

			if (s[a[x][0][i]] > s[x] + a[x][1][i]) {
				s[a[x][0][i]] = a[x][1][i] + s[x];
				f[a[x][0][i]] = x;
                node temp;

                q.push({a[x][0][i],s[a[x][0][i]]});
			}

    	}
	}
}
int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);
	cin >> n >> m >> st;
	for (int i = 1; i <= n; i++) s[i] = MAX;
	for (int i = 1; i <= m; i++) {
		int x, y, z;
		cin >> x >> y >> z;
        bool flag=1;
        for (int j = 0; j < a[x][0].size(); j++) {

			if (a[x][0][j]==y) {
                flag=0;
				a[x][1][j]=min(a[x][1][j],z);
			}

    	}
        if(flag){
		a[x][0].push_back(y);
		a[x][1].push_back(z);
        }
	}
	s[st] = 0;
    q.push({st, s[st]});
	di(st);
	for (int i = 1; i <= n; i++) cout << s[i] << " ";
	return 0;
}
